module RefModule(
    input clk,
    input rst,
    input en,
    output [3:0] count
);reg [3:0] unused_count_reg;

    always @(posedge clk) begin
        if (rst) begin
            unused_count_reg <= 4'b0;
        end else if (en) begin
            unused_count_reg <= unused_count_reg + 1;
        end
    end

    assign count = unused_count_reg;

endmodule
